// Parse sitemap XML to extract blog post URLs and lastmod dates
const xmlData = $input.item.json.data || $input.item.json.body || '';

// Simple XML parsing for sitemap entries
const urlEntries = [];
const urlRegex = /<url>([\s\S]*?)<\/url>/g;
let match;

while ((match = urlRegex.exec(xmlData)) !== null) {
  const block = match[1];

  const locMatch = block.match(/<loc>([^<]+)<\/loc>/);
  const lastmodMatch = block.match(/<lastmod>([^<]+)<\/lastmod>/);

  if (locMatch) {
    const url = locMatch[1].trim();
    const lastmod = lastmodMatch ? lastmodMatch[1].trim() : '';

    // Only include blog/article pages (adjust pattern to match your site)
    if (url.includes('/blog/') || url.includes('/posts/') || url.includes('/articles/')) {
      urlEntries.push({
        url: url,
        lastmod: lastmod
      });
    }
  }
}

// Sort by lastmod descending (newest first)
urlEntries.sort((a, b) => {
  if (!a.lastmod || !b.lastmod) return 0;
  return b.lastmod.localeCompare(a.lastmod);
});

// Take latest entries (max 10 for draft generation)
const latest = urlEntries.slice(0, 10);

if (latest.length === 0) {
  return [{ json: { _noNewPosts: true, message: '新しいブログ記事が見つかりませんでした' } }];
}

return latest.map(entry => ({ json: entry }));

// For each new blog post URL, generate a draft row with optimal posting times
// Distribute across Mon-Sat, using JST 7/12/18/21 time windows

const items = $input.all();
const now = new Date();
const jstOffset = 9 * 60 * 60 * 1000;
const jstNow = new Date(now.getTime() + jstOffset);

// Find next Monday
const dayOfWeek = jstNow.getUTCDay(); // 0=Sun
const daysUntilMonday = dayOfWeek === 0 ? 1 : (8 - dayOfWeek);
const nextMonday = new Date(jstNow);
nextMonday.setUTCDate(nextMonday.getUTCDate() + daysUntilMonday);
nextMonday.setUTCHours(0, 0, 0, 0);

// Posting time windows (JST hours)
const timeWindows = ['07:00', '12:00', '18:00', '21:00'];

// Days Mon(1) - Sat(6) = 6 days, 4 slots each = 24 slots per week
const days = [0, 1, 2, 3, 4, 5]; // offsets from Monday

const draftRows = [];
let slotIndex = 0;

for (const item of items) {
  const url = item.json.url || '';

  // Calculate day and time slot
  const dayOffset = days[slotIndex % days.length];
  const timeSlot = timeWindows[Math.floor(slotIndex / days.length) % timeWindows.length];

  // Calculate target date
  const targetDate = new Date(nextMonday);
  targetDate.setUTCDate(targetDate.getUTCDate() + dayOffset);
  const dateStr = targetDate.toISOString().split('T')[0]; // YYYY-MM-DD

  // Extract slug/title from URL for draft text
  const urlParts = url.split('/');
  const slug = urlParts[urlParts.length - 1] || urlParts[urlParts.length - 2] || 'article';
  const readableSlug = slug.replace(/-/g, ' ').replace(/_/g, ' ');

  // Generate draft templates based on category patterns
  const draftTemplates = [
    `📝 新しい記事を書きました！\n\n「${readableSlug}」\n\n詳しくはブログで 👇`,
    `💡 ${readableSlug}について解説しました！\n\nポイントをまとめています。`,
    `🔥 ブログ更新！\n\n${readableSlug}\n\n気になる方はチェックしてみてください！`
  ];

  const draftText = draftTemplates[slotIndex % draftTemplates.length];

  draftRows.push({
    json: {
      '日付': dateStr,
      '投稿時間': timeSlot,
      '投稿文': draftText,
      'カテゴリ': '記事紹介',
      'トピックタグ': 'ブログ,記事',
      '記事URL': url,
      '画像URL': '',
      'ステータス': '下書き',
      '投稿ID': '',
      'メモ': `自動生成: ${new Date().toISOString().split('T')[0]}`
    }
  });

  slotIndex++;
}

return draftRows;

// Prepare summary for Discord notification
const items = $input.all();
const now = new Date();
const jstOffset = 9 * 60 * 60 * 1000;
const jstDate = new Date(now.getTime() + jstOffset);
const todayStr = jstDate.toISOString().split('T')[0];

const draftCount = items.length;

// Group by date for summary
const byDate = {};
for (const item of items) {
  const date = item.json['日付'] || item.json.A || 'unknown';
  const time = item.json['投稿時間'] || item.json.B || '';
  if (!byDate[date]) byDate[date] = [];
  byDate[date].push(time);
}

const schedule = Object.entries(byDate)
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([date, times]) => `  ${date}: ${times.join(', ')}`)
  .join('\n');

const message = [
  `📋 **Threads投稿案 自動生成レポート** (${todayStr})`,
  ``,
  `✏️ 新規下書き: ${draftCount}件`,
  ``,
  `**配信スケジュール:**`,
  schedule,
  ``,
  `⚠️ スプレッドシートで内容を確認し、「承認済み」に変更してください。`,
  `---`,
  `自動生成 by n8n`
].join('\n');

return [{ json: { content: message } }];

// No new posts found
const now = new Date();
const jstOffset = 9 * 60 * 60 * 1000;
const jstDate = new Date(now.getTime() + jstOffset);
const todayStr = jstDate.toISOString().split('T')[0];

const message = `ℹ️ **Threads投稿案 自動生成** (${todayStr})\n\n新しいブログ記事が見つかりませんでした。\n既存の投稿スケジュールを確認してください。\n\n---\n自動生成 by n8n`;

return [{ json: { content: message } }];
